+fn probe_argfact(name: &str, flat: usize) -> String {
+    let k = (flat - name.len() - 8) / 5;
+    let l1 = flat - name.len() - 4 - 5 * k;
+    let long = format!("$q{}", "a".repeat(l1 - 2));
+    let mut elems = vec![long];
